const PAGE_SIZE = 4;

// ── Dropdown ─────────────────────────────────────────────────────────────────
function StatusDropdown({ value, onChange }) {
  const [open, setOpen] = useState(false);
  const ref = useRef(null);

  useEffect(() => {
    const handler = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  return (
    <div ref={ref} style={{ position: "relative" }}>
      <button
        onClick={() => setOpen((v) => !v)}
        style={{
          display: "flex", alignItems: "center", gap: 6,
          padding: "0 12px", height: 32, borderRadius: 6,
          background: "#F3F4F6", border: "1px solid #E5E7EB",
          fontSize: 11, fontWeight: 600, color: "#374151",
          cursor: "pointer", whiteSpace: "nowrap",
        }}
      >
        {value}
        <svg width="10" height="10" viewBox="0 0 10 10" fill="none">
          <path d="M2 3.5L5 6.5L8 3.5" stroke="#6B7280" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
        </svg>
      </button>

      {open && (
        <div style={{
          position: "absolute", top: "calc(100% + 4px)", right: 0, zIndex: 999,
          background: "#fff", border: "1px solid #E5E7EB", borderRadius: 8,
          boxShadow: "0 4px 16px rgba(0,0,0,0.10)", minWidth: 172, overflow: "hidden",
        }}>
          {DELIVERY_STATUSES.map((s) => (
            <button
              key={s}
              onClick={() => { onChange(s); setOpen(false); }}
              style={{
                display: "block", width: "100%", textAlign: "left",
                padding: "10px 16px", fontSize: 13, color: "#111827",
                background: s === value ? "#FEF3C7" : "transparent",
                border: "none", cursor: "pointer", fontFamily: "inherit",
              }}
              onMouseEnter={(e) => { if (s !== value) e.target.style.background = "#F9FAFB"; }}
              onMouseLeave={(e) => { if (s !== value) e.target.style.background = "transparent"; }}
            >
              {s}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

